mapper.select:
/* ChkLst03Mapper.selectChkptInspectItemList */ WITH SITE_LIST AS ( SELECT A.* FROM TB_SITE A INNER JOIN TB_USER_SITE_AUTH B ON ( A.CMPNY_CD = B.CMPNY_CD AND A.SITE_CD = B.SITE_CD AND B.USER_ID = #{param.userId} ) WHERE 1=1 AND A.CMPNY_CD = #{param.cmpnyCd} AND A.USE_YN = 'Y' AND ( A.END_DATE IS NULL OR A.END_DATE >= date_format(NOW(), '%y%m%d') ) )
SELECT '' AS chk , A.CMPNY_CD AS cmpnyCd , A.SITE_CD AS siteCd , A.SITE_NM AS siteNm , A.CHKPT_CD AS chkptCd , A.CHKPT_NM AS chkptNm , A.SITE_ADMIN_ID AS siteAdminId , B.USER_NM AS siteAdminNm , A.CHKLST_TYPE AS chkLstType , A.CHKPT_DESC AS chkptDesc , MIN(A.INSERT_DATE) AS WORK_DATE , COUNT(A.WORK_DATE) AS inspectDayCnt , SUM(A.N_ANSWER_CNT) AS defectiveResultCnt FROM ( SELECT A.CMPNY_CD , B.SITE_CD , B.SITE_NM , A.CHKPT_CD , A.CHKPT_NM , B.SITE_ADMIN_ID , C.CHKLST_TYPE , A.CHKPT_DESC , D.WORK_DATE , DATE_FORMAT(D.INSERT_DATE, '%Y-%m') AS INSERT_DATE , SUM(CASE WHEN D.INSPECT_ANSWER_TYPE = 'N' THEN 1 ELSE 0 END) AS N_ANSWER_CNT FROM TB_CHKPT_TYPE_MGMT A INNER JOIN SITE_LIST B ON ( A.CMPNY_CD = B.CMPNY_CD AND A.SITE_CD = B.SITE_CD ) INNER JOIN TB_CHKPT_INSPECT_ITEM C ON ( A.CMPNY_CD = C.CMPNY_CD AND A.CHKLST_TYPE = C.CHKLST_TYPE ) LEFT JOIN TB_CHKPT_INSPECT_ANSWER D ON ( A.CMPNY_CD = D.CMPNY_CD AND C.INSPECT_ITEM_CD = D.INSPECT_ITEM_CD AND A.SITE_CD = D.SITE_CD
AND SUBSTR(D.WORK_DATE, 1, 6) BETWEEN #{param.fromDate} AND #{param.toDate} ) WHERE A.CMPNY_CD = #{param.cmpnyCd} AND A.USE_YN = 'Y' GROUP BY A.CMPNY_CD , B.SITE_CD , A.CHKPT_CD , A.CHKPT_NM , C.CHKLST_TYPE , A.CHKPT_DESC , D.WORK_DATE , D.INSERT_DATE ) A INNER JOIN TB_USER B ON ( A.CMPNY_CD = B.CMPNY_CD AND A.SITE_ADMIN_ID = B.USER_ID AND B.USE_YN = 'Y' ) GROUP BY A.CMPNY_CD , A.SITE_CD , A.SITE_NM , A.CHKPT_CD , A.CHKPT_NM , A.SITE_ADMIN_ID , A.CHKLST_TYPE , A.CHKPT_DESC ORDER BY A.CMPNY_CD, A.CHKLST_TYPE

    /* ChkLst03Mapper.selectInspectItemSubjList */
    SELECT 
		B.INSPECT_ITEM_CD				AS inspectItemCd
	    , B.INSPECT_ITEM_SUBJ			AS inspectItemSubj
	FROM TB_CHKPT_TYPE_MGMT A
		INNER JOIN TB_CHKPT_INSPECT_ITEM B
			ON (
				A.CMPNY_CD = B.CMPNY_CD
			AND A.CHKLST_TYPE = B.CHKLST_TYPE
	        )
	WHERE A.CMPNY_CD = #{token.gv_cmpnyCd}
	  AND A.SITE_CD = #{param.siteCd}
	  AND A.CHKLST_TYPE = #{param.chkLstType}
	  AND A.CHKPT_CD = #{param.chkptCd}
